import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,e as n}from"./app-be253e4c.js";const c={},o=n(`<h1 id="tr命令" tabindex="-1"><a class="header-anchor" href="#tr命令" aria-hidden="true">#</a> tr命令</h1><p><code>tr</code>命令用于转换或删除文件中的字符，可以读文件也可以从标准输入设备读取数据，经过字符串转译后，将结果输出到标准输出设备。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">tr</span> <span class="token punctuation">[</span>OPTION<span class="token punctuation">]</span><span class="token punctuation">..</span>. SET1 <span class="token punctuation">[</span>SET2<span class="token punctuation">]</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-c, -C, --complement</code>: 使用<code>SET1</code>的补码。</li><li><code>-d, --delete</code>: 删除<code>SET1</code>中的字符，不翻译。</li><li><code>-s, --squeeze-repeats</code>: 用一次出现的字符替换<code>SET1</code>中列出的重复字符的每个输入序列。</li><li><code>-t, --truncate-set1</code>: 首先将<code>SET1</code>截断为<code>SET2</code>的长度。</li><li><code>--help</code>: 输出帮助信息。</li><li><code>--version</code>: 输出版本信息。</li></ul><h2 id="解释序列" tabindex="-1"><a class="header-anchor" href="#解释序列" aria-hidden="true">#</a> 解释序列</h2><ul><li><code>\\NNN</code>: 八进制值为<code>NNN</code>的字符(<code>1</code>到<code>3</code>个八进制数字)。</li><li><code>\\\\</code>: 反斜杠。</li><li><code>\\a</code>: 可闻的<code>BEL</code>。</li><li><code>\\b</code>: 退格键。</li><li><code>\\f</code>: 换页。</li><li><code>\\n</code>: 新行。</li><li><code>\\r</code>: 返回。</li><li><code>\\t</code>: 水平制表符。</li><li><code>\\v</code>: 垂直制表符。</li><li><code>CHAR1-CHAR2</code>: 从<code>CHAR1</code>到<code>CHAR2</code>的所有字符按升序排列。</li><li><code>[CHAR*]</code>: 在<code>SET2</code>中，复制<code>CHAR</code>直到<code>SET1</code>的长度。</li><li><code>[CHAR*REPEAT]</code>: 重复<code>CHAR</code>的副本，如果以<code>0</code>开头，则重复八进制。</li><li><code>[:alnum:]</code>: 所有字母和数字。</li><li><code>[:alpha:]</code>: 所有字母。</li><li><code>[:blank:]</code>: 所有水平空白。</li><li><code>[:cntrl:]</code>: 所有控制字符。</li><li><code>[:digit:]</code>: 所有数字。</li><li><code>[:graph:]</code>: 所有可打印字符，不包括空格。</li><li><code>[:lower:]</code>: 所有小写字母。</li><li><code>[:print:]</code>: 所有可打印字符，包括空格。</li><li><code>[:punct:]</code>: 所有标点符号。</li><li><code>[:space:]</code>: 所有水平或垂直空白。</li><li><code>[:upper:]</code>: 所有大写字母。</li><li><code>[:xdigit:]</code>: 所有十六进制数字。</li><li><code>[=CHAR=]</code>: 等同于<code>CHAR</code>的所有字符。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p><code>file.txt</code>文件内容如下。</p><div class="language-text" data-ext="text"><pre class="language-text"><code>Hello World
</code></pre></div><p>将文件中的字母全部转换为大写。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> file.txt <span class="token operator">|</span> <span class="token function">tr</span> <span class="token punctuation">[</span>a-z<span class="token punctuation">]</span> <span class="token punctuation">[</span>A-Z<span class="token punctuation">]</span>
<span class="token comment"># HELLO WORLD</span>
</code></pre></div><p>同样可以使用<code>[:lower]</code>与<code>[:upper]</code>参数来实现。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> file.txt <span class="token operator">|</span> <span class="token function">tr</span> <span class="token punctuation">[</span>:lower:<span class="token punctuation">]</span> <span class="token punctuation">[</span>:upper:<span class="token punctuation">]</span>
<span class="token comment"># HELLO WORLD</span>
</code></pre></div><p>将水平空白符转换为<code>\\t</code>。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> file.txt <span class="token operator">|</span> <span class="token function">tr</span> <span class="token punctuation">[</span>:space:<span class="token punctuation">]</span> <span class="token string">&quot;<span class="token entity" title="\\t">\\t</span>&quot;</span>
<span class="token comment"># Hello   World   </span>
</code></pre></div><p>删除所有<code>o</code>字符。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> file.txt <span class="token operator">|</span> <span class="token function">tr</span> <span class="token parameter variable">-d</span> <span class="token string">&quot;o&quot;</span>
<span class="token comment"># Hell Wrld</span>
</code></pre></div><p>删除所有数字。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> <span class="token string">&quot;My ID is 73535&quot;</span> <span class="token operator">|</span> <span class="token function">tr</span> <span class="token parameter variable">-d</span> <span class="token punctuation">[</span>:digit:<span class="token punctuation">]</span>
<span class="token comment"># My ID is</span>
</code></pre></div><p>取出字符串中的数字。</p><div class="language-text" data-ext="text"><pre class="language-text"><code>echo &quot;My ID is 73535&quot; | tr -cd [:digit:]
# 73535
</code></pre></div>`,23),t=[o];function d(l,p){return a(),s("div",null,t)}const u=e(c,[["render",d],["__file","tr.html.vue"]]);export{u as default};
